import { ethers } from "hardhat";

async function main() {
  try {
    console.log("Start decoding...");
    const callData = "";

    const safe7579Abi = [
      "function execute(bytes32 mode, bytes calldata executionCalldata) external"
    ];
    
    const iface = new ethers.Interface(safe7579Abi);
    const parsed = iface.decodeFunctionData("execute", callData);
    console.log("Mode:", parsed[0]);
    
    const hex = parsed[1].substring(2);
    console.log("ExecutionCalldata length:", hex.length / 2);
    
    // Let's decode it manually or step-by-step
    // Let's print the first 10 words
    for (let i = 0; i < Math.min(hex.length, 640); i += 64) {
      console.log(`Word ${i/64}: ${hex.substring(i, i+64)}`);
    }

    try {
      const batchAbi = [
        "tuple(address target, uint256 value, bytes callData)[]"
      ];
      const decodedCalls = ethers.AbiCoder.defaultAbiCoder().decode(
        batchAbi,
        parsed[1]
      )[0];
      console.log("Successfully decoded as batch. Calls count:", decodedCalls.length);
    } catch (e: any) {
      console.log("Batch decode failed:", e.message);
      
      // Let's try decoding it as single execution: (address to, uint256 value, bytes callData)
      try {
        const singleAbi = [
          "address",
          "uint256",
          "bytes"
        ];
        const decoded = ethers.AbiCoder.defaultAbiCoder().decode(singleAbi, parsed[1]);
        console.log("Successfully decoded as single:");
        console.log("  To:", decoded[0]);
        console.log("  Value:", decoded[1].toString());
        console.log("  Data length:", decoded[2].length);
      } catch (e2: any) {
        console.log("Single decode failed:", e2.message);
      }
    }
  } catch (err: any) {
    console.error("Outer error:", err);
  }
}

main().catch(console.error);
